6843   case ICmpInst::ICMP_UGT:
6844     // icmp ugt -> icmp ult
6845     std::swap(A, B);
6846     [[fallthrough]];
6847   case ICmpInst::ICMP_ULT:
6848     // icmp ult i1 A, B -> ~A & B
6849     return BinaryOperator::CreateAnd(Builder.CreateNot(A), B);
