4954 bool FCmpInst::compare(const APFloat &LHS, const APFloat &RHS,
4955                        FCmpInst::Predicate Pred) {
4956   APFloat::cmpResult R = LHS.compare(RHS);
4957   switch (Pred) {
4958   default:
4959     llvm_unreachable("Invalid FCmp Predicate");
4960   case FCmpInst::FCMP_FALSE:
4961     return false;
4962   case FCmpInst::FCMP_TRUE:
4963     return true;
4964   case FCmpInst::FCMP_UNO:
4965     return R == APFloat::cmpUnordered;
4966   case FCmpInst::FCMP_ORD:
4967     return R != APFloat::cmpUnordered;
4968   case FCmpInst::FCMP_UEQ:
4969     return R == APFloat::cmpUnordered || R == APFloat::cmpEqual;
4970   case FCmpInst::FCMP_OEQ:
4971     return R == APFloat::cmpEqual;
4972   case FCmpInst::FCMP_UNE:
4973     return R != APFloat::cmpEqual;
4974   case FCmpInst::FCMP_ONE:
4975     return R == APFloat::cmpLessThan || R == APFloat::cmpGreaterThan;
4976   case FCmpInst::FCMP_ULT:
4977     return R == APFloat::cmpUnordered || R == APFloat::cmpLessThan;
4978   case FCmpInst::FCMP_OLT:
4979     return R == APFloat::cmpLessThan;
4980   case FCmpInst::FCMP_UGT:
4981     return R == APFloat::cmpUnordered || R == APFloat::cmpGreaterThan;
4982   case FCmpInst::FCMP_OGT:
4983     return R == APFloat::cmpGreaterThan;
4984   case FCmpInst::FCMP_ULE:
4985     return R != APFloat::cmpGreaterThan;
4986   case FCmpInst::FCMP_OLE:
4987     return R == APFloat::cmpLessThan || R == APFloat::cmpEqual;
4988   case FCmpInst::FCMP_UGE:
4989     return R != APFloat::cmpLessThan;
4990   case FCmpInst::FCMP_OGE:
4991     return R == APFloat::cmpGreaterThan || R == APFloat::cmpEqual;
4992   }
